class Solution:
    def corpFlightBookings(self, bookings, n):
        diff = [0] * (n + 1)
        for a, b, s in bookings:
            diff[a - 1] += s
            diff[b] -= s
        ans = [0] * n
        running = 0
        for i in range(n):
            running += diff[i]
            ans[i] = running
        return ans

