var corpFlightBookings = function(bookings, n) {
    const diff = new Array(n + 1).fill(0);
    for (const [a, b, s] of bookings) {
        diff[a - 1] += s;
        diff[b] -= s;
    }
    const ans = new Array(n).fill(0);
    let running = 0;
    for (let i = 0; i < n; i++) {
        running += diff[i];
        ans[i] = running;
    }
    return ans;
};
